#include <stdio.h>
#define PI 3.14

int main() {
  float radius = 5.0;
  float area = PI * radius * radius;
  printf("Circle Area: %.2f square units\n", area);
  return 0;
}
// Output:
// Circle Area: 78.50 square units

#include <stdio.h>

int main() {
  const float DISCOUNT_RATE = 0.2;
  const int MAX_ITEMS = 100;
  float price = 50.0;
  float discount = price * DISCOUNT_RATE;
  printf("Original Price: $%.2f\n", price);
  printf("Discount: $%.2f\n", discount);
  printf("Max Items Allowed: %d\n", MAX_ITEMS);
  return 0;
}
// Output:
// Original Price: $50.00
// Discount: $10.00
// Max Items Allowed: 100

