#define GRAVITY 9.81

int main() {
  const int MAX_SPEED = 120;
  float height = 10.0;
  float velocity = GRAVITY * height;
  printf("Gravity: %.2f m/s^2\n", GRAVITY);
  printf("Max Speed: %d km/h\n", MAX_SPEED);
  printf("Velocity: %.2f m/s\n", velocity);
  return 0;
}
// Output:
// Gravity: 9.81 m/s^2
// Max Speed: 120 km/h
// Velocity: 98.10 m/s

